eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   researchProjects: () => (/* binding */ researchProjects)\n/* harmony export */ });\nconst researchProjects = [\n    {\n        slug: 'alumni-giving-prediction',\n        name: 'Alumni Giving Prediction',\n        timeframe: '2025',\n        discipline: 'Data Science / ML',\n        tools: [\n            'Python',\n            'XGBoost',\n            'Pandas'\n        ],\n        industry: 'Research',\n        excerpt: 'Predictive analysis of alumni giving behavior for Truman State University to support fundraising and development outreach.',\n        description: 'A predictive modeling project for Truman State University that analyzes alumni giving behavior to support development efforts. The work involved building and evaluating models on historical giving and demographic data, with attention to feature engineering, class imbalance, and interpretability for use in outreach planning.',\n        body: [\n            'This project applied predictive analytics to understand and model alumni giving behavior for Truman State University, in support of university fundraising. The goal was to provide development offices with a data-driven perspective on giving patterns while keeping the analysis appropriate for institutional use.',\n            {\n                type: 'heading',\n                text: 'What was done'\n            },\n            'Historical donation records and relevant demographic data were used to train and evaluate machine learning models. The work included designing and selecting features, handling imbalanced outcomes typical of giving data, and ensuring that model outputs could be interpreted and used responsibly for outreach planning.',\n            {\n                type: 'heading',\n                text: 'Approach'\n            },\n            'The pipeline was implemented in Python using standard data science and machine learning libraries. Emphasis was placed on reproducible preprocessing, model training, and interpretability so that results could be communicated clearly to non-technical stakeholders.',\n            {\n                type: 'heading',\n                text: 'Outcome'\n            },\n            'The project delivered a predictive analysis and supporting documentation suitable for use within Truman State University. It illustrates how data science can inform development strategy without disclosing sensitive or institution-specific findings.'\n        ],\n        links: [\n            {\n                label: 'Paper / Report',\n                url: ''\n            },\n            {\n                label: 'GitHub',\n                url: ''\n            }\n        ]\n    },\n    {\n        slug: 'enhancing-user-trust-ai-driven-hci',\n        name: 'Enhancing User Trust and Control in AI-Driven Interactive Human-Computer Interfaces',\n        timeframe: '2025',\n        discipline: 'Full Stack / AI',\n        tools: [\n            'React',\n            'PostgreSQL',\n            'AI'\n        ],\n        industry: 'Tech',\n        excerpt: 'Investigating how interface design and transparency affect user trust in AI systems.',\n        description: 'Research on how interface design and transparency mechanisms affect user trust and control when interacting with AI-driven systems. Includes a full-stack prototype for collecting user feedback and measuring trust metrics.',\n        body: [\n            'As AI is increasingly embedded in interactive systems, user trust and sense of control become critical for adoption and effective use. This research investigates how interface design and transparency mechanisms affect user trust when interacting with AI-driven human–computer interfaces.',\n            {\n                type: 'heading',\n                text: 'Goals'\n            },\n            'The project aims to identify design patterns and interaction techniques that enhance both perceived trust and actual user control—for example, through explainable AI outputs, adjustable automation levels, and clear feedback. A secondary goal is to provide measurable trust metrics that can guide design decisions.',\n            {\n                type: 'heading',\n                text: 'Approach'\n            },\n            'We built a full-stack prototype that presents users with AI-assisted tasks and collects behavioral and self-reported data. The frontend is implemented in React to support rich, responsive interactions; the backend uses PostgreSQL for storing user responses and derived trust metrics. The system supports A/B testing of different transparency and control mechanisms.',\n            {\n                type: 'heading',\n                text: 'Outcomes'\n            },\n            'Findings inform how transparency, controllability, and feedback design influence trust in AI-driven interfaces. The prototype serves as a reusable platform for running studies and iterating on interface design for AI systems.'\n        ],\n        links: [\n            {\n                label: 'Download PDF',\n                url: '/research/Enhancing-User-Trust-AI-Driven-HCI.pdf'\n            },\n            {\n                label: 'Demo',\n                url: ''\n            }\n        ]\n    },\n    {\n        slug: 'vista-med',\n        name: 'VISTA-MED',\n        timeframe: '2026',\n        discipline: 'AI & VR / Medical Education',\n        tools: [\n            'Python',\n            'nnU-Net',\n            'Unity',\n            'Virtual Reality',\n            'BRATS2020'\n        ],\n        industry: 'Healthcare',\n        excerpt: 'AI-VR platform combining nnU-Net brain tumor segmentation with Unity-based virtual reality for interactive medical imaging education.',\n        description: 'VISTA-MED is an integrated platform that combines AI-based MRI segmentation with virtual reality for medical education. It uses nnU-Net for brain tumor segmentation on BRATS2020 data and a Unity-based VR environment for interactive spatial exploration of anatomical structures, addressing limitations of traditional 2D anatomy instruction.',\n        body: [\n            'VISTA-MED is an integrated AI–VR platform that combines artificial intelligence with virtual reality to enhance medical imaging education. Published in Springer’s Discover Education, it addresses limitations of traditional anatomy instruction by enabling interactive spatial exploration of medical images in an immersive environment.',\n            {\n                type: 'heading',\n                text: 'Technical implementation'\n            },\n            'The system uses the nnU-Net architecture for automated segmentation of brain tumors from the BRATS2020 dataset. The preprocessing pipeline includes bias field correction, image registration to the MNI152 template, and noise reduction. Segmentation outputs are converted into 3D-compatible formats and integrated into a Unity-based VR environment, enabling real-time, interactive exploration of anatomical structures.',\n            {\n                type: 'heading',\n                text: 'Results'\n            },\n            'The AI segmentation model achieved a mean Dice score of 0.914–0.917, indicating high accuracy in tumor boundary delineation. Internal testing confirmed smooth rendering and stable frame rates in the VR environment, with real-time interaction and no noticeable latency.',\n            {\n                type: 'heading',\n                text: 'Educational impact'\n            },\n            'VISTA-MED enhances spatial understanding and diagnostic reasoning by providing immersive visualization of segmented MRI data. The work establishes a foundation for broader adoption, with planned focus on usability studies, scalability, and educational impact assessment in clinical and academic settings.'\n        ],\n        links: [\n            {\n                label: 'Read on ResearchGate',\n                url: 'https://www.researchgate.net/publication/400985902_VISTA-MED_integrating_AI-based_MRI_segmentation_with_virtual_reality_for_medical_education'\n            },\n            {\n                label: 'Live App',\n                url: ''\n            },\n            {\n                label: 'Documentation',\n                url: ''\n            }\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./src/data/research.js\n");

